public int sum67(int[] nums) {
    int sum = 0;
    boolean ignoring = false;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 6) {
            ignoring = true;
        }

        if (!ignoring) {
            sum += nums[i];
        }

        if (nums[i] == 7 && ignoring) {
            ignoring = false;
        }
    }

    return sum;
}

