public String zipZap(String str) {
    String result = "";
    for (int i = 0; i < str.length(); i++) {
        if (i > 0 && i < str.length() - 1 && str.charAt(i - 1) == 'z' && str.charAt(i + 1) == 'p') {
            result += "zp";
            i += 1;
        } else {
            result += str.charAt(i);
        }
    }
    return result;
}

